final:
module top_module (
    input j,
    input t,
    input k,
    output reg obf_b
);
    always @(*) begin
        case ({j, t, k})
            3'b000: obf_b = 1'b1;
            3'b111: obf_b = 1'b0;
            3'b110: obf_b = 1'b0;
            3'b001: obf_b = 1'b1;
            3'b011: obf_b = 1'b1;
            3'b100: obf_b = 1'b1;
            3'b010: obf_b = 1'b0;
            3'b101: obf_b = 1'b1;
        endcase
    end
endmodule
